    """
    Wrapper to keep the secondary dictionary, `_column_requires_decoding`, of the `Features` class in sync
    with the main dictionary.

    A regular dictionary subclass isn't used since it would force us to re-implement every dictionary method
    that can mutate the mapping (`UserDict` triggers a wasteful full re-computation, and a plain `dict` subclass
    would silently fall out of sync on inherited/unwrapped methods), so this decorator is applied to every
    `Features` method that can add, remove or replace a column instead.
    """

    @wraps(func)
    def wrapper(*args, **kwargs):
        if args:
            self: "Features" = args[0]
        else:
            self: "Features" = kwargs["self"]
        out = func(*args, **kwargs)
        assert hasattr(self, "_column_requires_decoding")
        self._column_requires_decoding = {col: require_decoding(feature) for col, feature in self.items()}
        return out

    wrapper._decorator_name_ = "keep_features_dicts_synced"
    return wrapper


